module top_module(
    input [7:0] a, b,
    input [1:0] op,
    output reg [7:0] error_result
);always @(*) begin
    case(op)
        2'b00: error_result = a + b;
        2'b01: error_result = a - b;
        2'b10: error_result = a * b;
        2'b11: error_result = a / b;
    endcase
end

endmodule
